import{c as i,Z as n,Q as p,j as t,o as l,m as e}from"./chunks/framework.qjzPVSkb.js";const u=JSON.parse('{"title":"用 AI 做数据整理","description":"从 CSV 到分析报告——让 AI 帮你理解、清洗、分析和可视化数据","frontmatter":{"title":"用 AI 做数据整理","description":"从 CSV 到分析报告——让 AI 帮你理解、清洗、分析和可视化数据","difficulty":"beginner"},"headers":[],"relativePath":"practices/ai-data-analysis.md","filePath":"practices/ai-data-analysis.md"}'),h={name:"practices/ai-data-analysis.md"};function k(r,s,d,o,c,g){const a=n("DifficultyBadge");return p(),t("div",null,[l(a,{level:"beginner"}),s[0]||(s[0]=e(`<h1 id="用-ai-做数据整理" tabindex="-1">用 AI 做数据整理 <a class="header-anchor" href="#用-ai-做数据整理" aria-label="Permalink to &quot;用 AI 做数据整理&quot;">​</a></h1><p>面对一张上千行的 Excel 表格不知道该从哪下手？让 AI 来帮你。从理解数据结构到生成分析报告，不用写一行代码，也能做专业级的数据分析。</p><h2 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h2><ul><li>一份 CSV 或 Excel 数据文件</li><li>一个能上传文件的 AI 工具（ChatGPT Plus、Claude Pro、DeepSeek 等）</li><li>明确你分析的目标（比如&quot;找出销售趋势&quot;&quot;分析用户行为&quot;）</li></ul><hr><h2 id="第-1-步-上传数据-让-ai-理解结构" tabindex="-1">第 1 步：上传数据，让 AI 理解结构 <a class="header-anchor" href="#第-1-步-上传数据-让-ai-理解结构" aria-label="Permalink to &quot;第 1 步：上传数据，让 AI 理解结构&quot;">​</a></h2><p>先把数据喂给 AI，让它理解每一列是什么意思。这一步很关键，AI 理解了数据含义，后续分析才会准确。</p><h3 id="示例-prompt" tabindex="-1">示例 Prompt <a class="header-anchor" href="#示例-prompt" aria-label="Permalink to &quot;示例 Prompt&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我上传了一份公司 2025 年 Q1-Q4 的销售数据 CSV 文件。</span></span>
<span class="line"><span>请帮我理解这份数据的结构：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 一共有多少行、多少列？</span></span>
<span class="line"><span>2. 每一列的名称和数据类型是什么？</span></span>
<span class="line"><span>3. 有哪些列可能存在空值？</span></span>
<span class="line"><span>4. 根据列名，你判断这份数据是用来做什么的？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请用中文回答，列出分析结果。</span></span></code></pre></div><p>AI 会输出数据的概览。如果你对它理解的列含义不满意，及时纠正：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;amount&quot; 这一列不是金额，是订单数量。请更正你的理解。</span></span></code></pre></div><hr><h2 id="第-2-步-让-ai-做数据清洗" tabindex="-1">第 2 步：让 AI 做数据清洗 <a class="header-anchor" href="#第-2-步-让-ai-做数据清洗" aria-label="Permalink to &quot;第 2 步：让 AI 做数据清洗&quot;">​</a></h2><p>原始数据通常很&quot;脏&quot;——有重复行、空值、格式不一致。让 AI 帮你洗数据。</p><h3 id="示例-prompt-1" tabindex="-1">示例 Prompt <a class="header-anchor" href="#示例-prompt-1" aria-label="Permalink to &quot;示例 Prompt&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请用 Python 对这份数据做清洗，具体任务：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 删除完全重复的行</span></span>
<span class="line"><span>2. 检查 &quot;price&quot; 列是否都是数字格式，如果不是请修正</span></span>
<span class="line"><span>3. &quot;date&quot; 列统一成 YYYY-MM-DD 格式</span></span>
<span class="line"><span>4. 如果某行的 &quot;customer_name&quot; 为空，填充为 &quot;未知客户&quot;</span></span>
<span class="line"><span>5. 删除 &quot;price&quot; 为 0 或负数的异常行</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请输出清洗后的数据摘要（行数变化、修改了哪些值），以及清洗用的 Python 代码。</span></span></code></pre></div><p>AI 会输出清洗代码和统计结果：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pandas </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pd</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">df </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pd.read_csv(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;sales_data.csv&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 删除重复行</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">before </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> len</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(df)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">df </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> df.drop_duplicates()</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;删除了 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">{</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">before </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> len</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(df)</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 行重复数据&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 统一日期格式</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">df[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;date&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pd.to_datetime(df[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;date&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]).dt.strftime(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;%Y-%m-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">%d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 填充空值</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">df[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;customer_name&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> df[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;customer_name&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">].fillna(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;未知客户&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 删除异常行</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">df </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> df[df[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;price&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;清洗后剩余 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">{len</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(df)</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 行数据&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>把代码复制到本地 Python 环境运行，或者直接在 ChatGPT/Claude 的代码执行环境中跑。</p><hr><h2 id="第-3-步-让-ai-做分析" tabindex="-1">第 3 步：让 AI 做分析 <a class="header-anchor" href="#第-3-步-让-ai-做分析" aria-label="Permalink to &quot;第 3 步：让 AI 做分析&quot;">​</a></h2><p>数据干净了，开始真正的分析。带着问题去问 AI，比让它&quot;随便分析一下&quot;效果好得多。</p><h3 id="示例-prompt-2" tabindex="-1">示例 Prompt <a class="header-anchor" href="#示例-prompt-2" aria-label="Permalink to &quot;示例 Prompt&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基于刚才清洗后的销售数据，请帮我做以下分析：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 按季度统计总销售额，观察趋势（上升还是下降？）</span></span>
<span class="line"><span>2. 找出销售额前 5 的产品</span></span>
<span class="line"><span>3. 分析客户复购率（同一客户购买多次的比例）</span></span>
<span class="line"><span>4. 检查有没有异常大单（单笔金额超过平均值 3 倍标准差的记录）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每个分析结果请给出你的解读，不只是数据，还要说明&quot;这意味着什么&quot;。</span></span></code></pre></div><p>AI 会逐一计算并给出结论。对于不确定的判断，你可以追问：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你提到 Q3 销售额下降了 12%，这算是正常波动还是异常信号？</span></span>
<span class="line"><span>结合完整年份的数据来判断一下。</span></span></code></pre></div><hr><h2 id="第-4-步-让-ai-生成可视化方案和报告" tabindex="-1">第 4 步：让 AI 生成可视化方案和报告 <a class="header-anchor" href="#第-4-步-让-ai-生成可视化方案和报告" aria-label="Permalink to &quot;第 4 步：让 AI 生成可视化方案和报告&quot;">​</a></h2><p>分析做完了，要把结果呈现出来。告诉 AI 你的受众是谁，它会推荐合适的图表类型。</p><h3 id="可视化建议-prompt" tabindex="-1">可视化建议 Prompt <a class="header-anchor" href="#可视化建议-prompt" aria-label="Permalink to &quot;可视化建议 Prompt&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我需要把这些分析结果做成一份报告，面向公司管理层（非技术人员）。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请为下面的每个分析结果推荐一种图表类型：</span></span>
<span class="line"><span>1. 季度销售额趋势 → ___</span></span>
<span class="line"><span>2. 前 5 产品对比 → ___</span></span>
<span class="line"><span>3. 客户复购率 → ___</span></span>
<span class="line"><span>4. 异常订单分析 → ___</span></span>
<span class="line"><span></span></span>
<span class="line"><span>对每个推荐，说明为什么选这种图（比如&quot;趋势用折线图，因为强调时间变化&quot;）。</span></span></code></pre></div><h3 id="生成报告-prompt" tabindex="-1">生成报告 Prompt <a class="header-anchor" href="#生成报告-prompt" aria-label="Permalink to &quot;生成报告 Prompt&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基于以上全部分析结果，请帮我写一份数据分析报告。</span></span>
<span class="line"><span>要求：</span></span>
<span class="line"><span>- 标题：2025 年度销售数据分析报告</span></span>
<span class="line"><span>- 结构：摘要 → 整体趋势 → 产品表现 → 客户分析 → 问题发现 → 建议</span></span>
<span class="line"><span>- 语言：简洁专业，每个观点配数据支撑</span></span>
<span class="line"><span>- 篇幅：800 字左右</span></span></code></pre></div><hr><h2 id="关键技巧总结" tabindex="-1">关键技巧总结 <a class="header-anchor" href="#关键技巧总结" aria-label="Permalink to &quot;关键技巧总结&quot;">​</a></h2><ol><li><strong>先让 AI 理解数据</strong>：告诉它每列的含义和数据类型，后续分析才准确</li><li><strong>清洗后再分析</strong>：脏数据直接分析，结论不可靠</li><li><strong>带具体问题去问</strong>：&quot;帮我分析&quot;不如&quot;帮我看销售额趋势、找前 5 产品、检查异常值&quot;</li><li><strong>让 AI 解读，不只是计算</strong>：要求它对每个结果给出&quot;这意味着什么&quot;</li><li><strong>敏感数据脱敏后再上传</strong>：客户姓名、手机号等隐私信息先处理掉</li></ol><hr><h2 id="关联阅读" tabindex="-1">关联阅读 <a class="header-anchor" href="#关联阅读" aria-label="Permalink to &quot;关联阅读&quot;">​</a></h2><ul><li><a href="/ai-knowledge/tools/chatgpt.html">ChatGPT 工具详解</a></li><li><a href="/ai-knowledge/practices/chatgpt-coding.html">用 AI 辅助编程</a></li><li><a href="/ai-knowledge/practices/ai-translation.html">用 AI 做翻译</a></li></ul>`,39))])}const y=i(h,[["render",k]]);export{u as __pageData,y as default};
